import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const API = "http://localhost:5000/api";

const STEPS = [
  'Care Type',
  'Patient Details',
  'Requirements',
  'Schedule',
  'Location',
  'Select Caregiver',
  'Review'
];

const initialForm = {
  careType: '',
  patient: { name: '', age: '', gender: '', medicalConditions: '' },
  careRequirements: [],
  schedule: { startDate: '', duration: '' },
  location: { address: '' },
  additionalNotes: ''
};

export default function BookingForm() {
  const [step, setStep] = useState(0);
  const [form, setForm] = useState(initialForm);
  const [caregivers, setCaregivers] = useState([]);
  const [caregiverId, setCaregiverId] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    axios.get(`${API}/caregivers`)
      .then(res => setCaregivers(res.data))
      .catch(err => console.log(err));
  }, []);

  const setPatient = (f, v) => setForm(p => ({ ...p, patient: { ...p.patient, [f]: v } }));
  const setSchedule = (f, v) => setForm(p => ({ ...p, schedule: { ...p.schedule, [f]: v } }));
  const setLocation = (f, v) => setForm(p => ({ ...p, location: { ...p.location, [f]: v } }));

  const canNext = () => {
    if (step === 0) return form.careType;
    if (step === 1) return form.patient.name && form.patient.age && form.patient.gender;
    if (step === 2) return form.careRequirements.length > 0;
    if (step === 3) return form.schedule.startDate && form.schedule.duration;
    if (step === 4) return form.location.address;
    if (step === 5) return caregiverId;
    return true;
  };

  const handleSubmit = async () => {
    const token = localStorage.getItem("token");

    // ✅ TOKEN CHECK
    if (!token) {
      alert("Please login first");
      navigate('/login');
      return;
    }

    try {
      await axios.post(
        `${API}/bookings`,
        {
          caregiverId,
          careType: form.careType,
          patient: form.patient,
          careRequirements: form.careRequirements,
          schedule: form.schedule,
          location: form.location,
          additionalNotes: form.additionalNotes
        },
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      alert("Booking Successful!");
      navigate('/dashboard');

    } catch (err) {
      console.log("BOOKING ERROR:", err.response?.data || err.message);
      alert(err.response?.data?.message || "Booking failed");
    }
  };

  return (
    <div className="main-content">
      <h1>Book a Caregiver</h1>
      <h3>Step {step + 1}: {STEPS[step]}</h3>

      {/* STEP 0 */}
      {step === 0 && (
        <select onChange={(e) => setForm({ ...form, careType: e.target.value })}>
          <option value="">Select Care Type</option>
          <option value="elderly">Elderly</option>
          <option value="maternity">Pregnant Woman</option>
          <option value="childcare">Child</option>
        </select>
      )}

      {/* STEP 1 */}
      {step === 1 && (
        <>
          <input placeholder="Name" onChange={e => setPatient('name', e.target.value)} />
          <input type="number" placeholder="Age" onChange={e => setPatient('age', e.target.value)} />
          <select onChange={e => setPatient('gender', e.target.value)}>
            <option value="">Gender</option>
            <option value="male">Male</option>
            <option value="female">Female</option>
          </select>
        </>
      )}

      {/* STEP 2 */}
      {step === 2 && (
        <button onClick={() =>
          setForm(p => ({ ...p, careRequirements: ['daily_assistance'] }))
        }>
          Add Requirement
        </button>
      )}

      {/* STEP 3 */}
      {step === 3 && (
        <>
          <input type="date" onChange={e => setSchedule('startDate', e.target.value)} />
          <select onChange={e => setSchedule('duration', e.target.value)}>
            <option value="">Duration</option>
            <option value="4 hours">4 hours</option>
            <option value="8 hours">8 hours</option>
          </select>
        </>
      )}

      {/* STEP 4 */}
      {step === 4 && (
        <input placeholder="Address" onChange={e => setLocation('address', e.target.value)} />
      )}

      {/* STEP 5 */}
      {step === 5 && (
        <select value={caregiverId} onChange={(e) => setCaregiverId(e.target.value)}>
          <option value="">Select Caregiver</option>
          {caregivers.map(cg => (
            <option key={cg._id} value={cg._id}>
              {cg.user?.name}
            </option>
          ))}
        </select>
      )}

      {/* STEP 6 */}
      {step === 6 && (
        <div>
          <p>Care Type: {form.careType}</p>
          <p>Patient: {form.patient.name}</p>
        </div>
      )}

      <br />

      {step > 0 && <button onClick={() => setStep(step - 1)}>Back</button>}

      {step < STEPS.length - 1 ? (
        <button onClick={() => setStep(step + 1)} disabled={!canNext()}>
          Next
        </button>
      ) : (
        <button onClick={handleSubmit}>Submit</button>
      )}
    </div>
  );
}
